exercises.solution_code:
#include <array>
#include <cstddef>
#include <iostream>

int main()
{
    std::array<int, 6> arr{};

    for (auto it{ arr.begin() }; it != arr.end(); ++it)
        std::cin >> *it;

    int max{ *arr.begin() };
    std::size_t position{ 0 };

    for (auto it{ arr.begin() }; it != arr.end(); ++it)
    {
        if (*it > max)
        {
            max = *it;
            position = static_cast<std::size_t>(it - arr.begin());
        }
    }

    std::cout << "Max: " << max << '\n';
    std::cout << "Position: " << position << '\n';

    return 0;
}
